const axios = require('axios');

/**
 * Verifies a National Identity Number (NIN) using Prembly API.
 * 
 * @param {string} ninNumber - The NIN to verify.
 * @returns {Promise<Object>} - The data object from the API response.
 */
async function verifyNIN(ninNumber) {
    const url = 'https://api.prembly.com/verification/vnin';
    const appId = process.env.PREMBLY_APP_ID;
    const apiKey = process.env.PREMBLY_API_KEY;

    try {
        const response = await axios.post(url, {
            number: ninNumber
        }, {
            headers: {
                'app-id': appId,
                'x-api-key': apiKey,
                'Content-Type': 'application/json'
            }
        });

        return response.data;
    } catch (error) {
        // Re-throw the error or handle it as needed. 
        // For this implementation, we'll let the caller handle exceptions.
        if (error.response) {
            // The request was made and the server responded with a status code
            // that falls out of the range of 2xx
            return error.response.data;
        }
        throw error;
    }
}

module.exports = { verifyNIN };

